mongodb:createCollection.mongodb:options:
{
    validator: {
        $jsonSchema: {
        bsonType: "object",
        title: "Payments collection with validator",
        required: ["order_id", "user_id", "status", "timestamp", "payment_amount"],
        properties: {
            order_id: {
                bsonType: "long"
            },
            user_id: {
                bsonType: "long"
            },
            status: {
                bsonType: "string",
                enum: ["COMPLETED", "FAILED"]
            },
            timestamp: {
                bsonType: "timestamp"
            },
            payment_amount: {
                bsonType: "decimal",
                minimum: 0
            }
        }
    }
},
    validationAction: "error",
    validationLevel: "strict"
}
